const meta = $.steps.listDriveFiles.response || {};
const content = $.steps.exportFile.response || '';
const docText = (typeof content === 'string') ? content : JSON.stringify(content);
const fileName = meta.name || 'unknown_document';
const now = new Date().toISOString();
return {
  fileName: fileName,
  content: docText.slice(0, 50000),
  contentLength: docText.length,
  createdAt: now
};

const d = $.steps.prepareContent.output;
const table = $.input.tableName || 'documents';
const escaped = d.content.replace(/'/g, "''").slice(0, 30000);
const query = "INSERT INTO " + table + " (file_name, content, created_at) VALUES ('" + d.fileName.replace(/'/g, "''") + "', '" + escaped + "', '" + d.createdAt + "') ON CONFLICT (file_name) DO UPDATE SET content = EXCLUDED.content, created_at = EXCLUDED.created_at RETURNING id, file_name;";
return { query };

const d = $.steps.prepareContent.output;
const question = $.input.question;
if (!question || question.trim().length === 0) {
  return { prompt: '', skip: true };
}
let prompt = 'You are a document analyst. Answer the following question based on the document content.\n\n';
prompt += 'DOCUMENT: ' + d.fileName + '\n\n';
prompt += 'CONTENT:\n' + d.content.slice(0, 15000) + '\n\n';
prompt += 'QUESTION: ' + question + '\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "detailed answer",\n';
prompt += '  "relevantExcerpts": ["excerpt1", "excerpt2"],\n';
prompt += '  "confidence": "high|medium|low"\n';
prompt += '}';
return { prompt, skip: false };

let raw = $.steps.aiRetrieve.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw || 'Document stored successfully (no question asked)', relevantExcerpts: [], confidence: 'medium' }; }

const d = $.steps.prepareContent.output;
const ai = $.steps.parseAI.output;
const question = $.input.question;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Supabase Document Operation', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Document:* ' + d.fileName + ' (' + d.contentLength + ' chars)' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Status:* Stored in Supabase table `' + ($.input.tableName || 'documents') + '`' } });

if (question && question.trim().length > 0) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Q:* ' + question } });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*A:* ' + (ai.answer || 'No answer').slice(0, 1000) } });
  if (ai.confidence) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Confidence: ' + ai.confidence }] });
  }
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Drive + Supabase + Claude AI' }] });

const fallback = 'Supabase: ' + d.fileName + ' stored, ' + d.contentLength + ' chars';
return { blocks, fallback };
